async (params, browser) => {
  // Open page
  await browser.open(`https://www.strava.com/routes/${params.route_id}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="Route"], .route-heading', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1, [class*="RouteName"]')?.textContent?.trim()||''; const stats = {}; document.querySelectorAll('[class*="Stat"], .stat, .route-stats span').forEach(el => { const text = el.textContent.trim(); if(text.length<60) { const parts = text.split(':').map(s=>s.trim()); if(parts.length===2) stats[parts[0].toLowerCase()]=parts[1]; } }); const creator = document.querySelector('a[href*="/athletes/"], [class*="Creator"]')?.textContent?.trim()||''; return { route_id: '' + params.route_id + '', name, stats, creator, url: window.location.href }`)

  return page_data
}
